import java.io.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter your name: ");
            String userName = reader.readLine();

            // Fixing XSS vulnerability: encoding user input before outputting
            String encodedUserName = Encode.forHtml(userName);

            System.out.println("Hello, " + encodedUserName + "! Welcome to our website.");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
